import React, { useState, useEffect } from 'react';
import styled, { keyframes } from 'styled-components';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  fetchLiveMetalsPrices, 
  subscribeToMetalsUpdates, 
  MetalsData, 
  MetalPrice,
  ChartData,
  calculateIndicators
} from '../services/metalsApi';
import { getStaticHistoricalData } from '../services/staticHistoricalData';
import CorrelationChart from '../components/CorrelationChart';
import PriceTrendChart from '../components/PriceTrendChart';
import MetalsPredictionChart from '../components/MetalsPredictionChart';

const GoldSilverContainer = styled.div`
  max-width: 1200px;
  margin: 0 auto;
  padding: 2rem;
  min-height: 80vh;
`;

const PageTitle = styled(motion.h1)`
  font-size: 3rem;
  margin-bottom: 3rem;
  font-weight: 800;
  letter-spacing: -1.5px;
  background: ${props => props.theme.colors.accentPrimary};
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
`;

const MetalsGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
  gap: 2rem;
  margin-bottom: 3rem;
`;

const shimmer = keyframes`
  0% { background-position: -200% 0; }
  100% { background-position: 200% 0; }
`;

const MetalCard = styled(motion.div)<{ glowcolor?: string }>`
  background: ${props => props.theme.colors.cardBackground};
  border-radius: ${props => props.theme.borderRadius.large};
  padding: 2.5rem;
  border: 1px solid ${props => props.theme.colors.border};
  backdrop-filter: blur(10px);
  position: relative;
  overflow: hidden;

  &::after {
    content: '';
    position: absolute;
    bottom: 0;
    left: 0;
    width: 100%;
    height: 4px;
    background: ${props => props.theme.colors.accentPrimary};
    opacity: 0.5;
  }
`;

const MetalHeader = styled.div`
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 1rem;
  margin-bottom: 1.5rem;
`;

const MetalIcon = styled(motion.div)`
  font-size: 3rem;
  filter: drop-shadow(0 0 10px rgba(255, 255, 255, 0.3));
`;

const MetalName = styled.h2`
  font-size: 1.2rem;
  color: ${props => props.theme.colors.textSecondary};
  margin-bottom: 1rem;
  text-transform: uppercase;
  letter-spacing: 2px;
  font-weight: 700;
`;

const LiveIndicator = styled(motion.div)`
